const source = {
  transcript: "transcript",
  screenshot: "screenshot identifiable",
  seed: "seed expansion"
};

function game(title, micro, meso, macro, options = {}) {
  const initials = title
    .replace(/[^a-zA-Z0-9 ]/g, "")
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((word) => word[0])
    .join("")
    .toUpperCase();

  return {
    title,
    initials,
    micro,
    meso,
    macro,
    immersion: options.immersion ?? 50,
    navigation: options.navigation ?? 70,
    friction: options.friction ?? 45,
    teamReliance: options.teamReliance ?? 35,
    stress: options.stress ?? 45,
    novelty: options.novelty ?? 60,
    story: options.story ?? 45,
    cozy: options.cozy ?? 35,
    creativity: options.creativity ?? 40,
    exploration: options.exploration ?? 50,
    steamId: options.steamId ?? "",
    link: options.link ?? "",
    mode: options.mode ?? "mixed",
    pacing: options.pacing ?? "medium",
    source: options.source ?? source.seed,
    tags: options.tags ?? [],
    note: options.note ?? "",
  };
}

